(window.webpackJsonp=window.webpackJsonp||[]).push([[56],{852:function(r,n,t){"use strict";t.r(n),n.default="// Author @patriciogv - 2015 - patricio.io\r\n\r\n#ifdef GL_ES\r\nprecision mediump float;\r\n#endif\r\n\r\nconst float PI = 3.1415926535897932384626433832795;\r\n\r\nuniform vec2 dd_resolution;\r\nuniform vec2 dd_mouse;\r\nuniform float dd_time;\r\n\r\nvec2 movingTiles(vec2 _st, float _zoom, float _speed){\r\n    _st *= _zoom;\r\n    float time = dd_time*_speed;\r\n    if( fract(time)>0.5 ){\r\n        if (fract( _st.y * 0.5) > 0.5){\r\n            _st.x += fract(time)*2.0;\r\n        } else {\r\n            _st.x -= fract(time)*2.0;\r\n        }\r\n    } else {\r\n        if (fract( _st.x * 0.5) > 0.5){\r\n            _st.y += fract(time)*2.0;\r\n        } else {\r\n            _st.y -= fract(time)*2.0;\r\n        }\r\n    }\r\n    return fract(_st);\r\n}\r\n\r\nfloat circle(vec2 _st, float _radius){\r\n    vec2 pos = vec2(0.5)-_st;\r\n    return smoothstep(1.0-_radius,1.0-_radius+_radius*0.2,1.-dot(pos,pos)*3.14);\r\n}\r\n\r\nvoid main() {\r\n    vec2 st = gl_FragCoord.xy/dd_resolution.xy;\r\n    st.x *= dd_resolution.x/dd_resolution.y;\r\n\r\n    st = movingTiles(st,10.,0.5);\r\n\r\n    vec3 color = vec3( 1.0-circle(st, 0.3 ) );\r\n\r\n    gl_FragColor = vec4(color,1.0);\r\n}\r\n"}}]);